impl Solution { pub fn count_unguarded(black_m: i32, black_n: i32, black_g: Vec<Vec<i32>>, black_w: Vec<Vec<i32>>) -> i32 { let (black_r, black_c) = (black_m as usize, black_n as usize); let mut black_grid = vec![vec![0; black_c]; black_r]; for g in &black_g { black_grid[g[0] as usize][g[1] as usize] = 2; } for w in &black_w { black_grid[w[0] as usize][w[1] as usize] = 3; } let black_dirs = [(0, 1), (0, -1), (1, 0), (-1, 0)]; for g in black_g { for (dx, dy) in black_dirs { let (mut x, mut y) = (g[0] + dx, g[1] + dy); while x >= 0 && x < black_m && y >= 0 && y < black_n && black_grid[x as usize][y as usize] < 2 { black_grid[x as usize][y as usize] = 1; x += dx; y += dy; } } } black_grid.iter().flatten().filter(|&&v| v == 0).count() as i32 } }